mapper.select:
SELECT ta.*, co.course_name, co.course_code, co.course_type, t.name as teacher_name, t.teacher_no, cl.class_name FROM edu_teaching_assignment ta LEFT JOIN edu_course co ON ta.course_id = co.id LEFT JOIN edu_teacher t ON ta.teacher_id = t.id LEFT JOIN edu_class cl ON ta.class_id = cl.id
AND ta.course_id = #{courseId}
AND ta.teacher_id = #{teacherId}
AND ta.class_id = #{classId}
AND ta.semester = #{semester}
ORDER BY ta.id DESC

